import express
from flask import Flask
app = Flask(__name__)
@app.route('/users/<id>', methods=['GET'])
def get_user_data(id):
  try:
    id = int(id)
    if id <= 0:
      return { error: 'Invalid user ID' }
    return { name: 'John Doe', email: 'johndoe@example.com' }
  except ValueError:
    return { error: 'Invalid user ID' }
